const fs = require('fs');
const path = require('path');

// Target path for the output fallback articles database
const outputPath = path.join(__dirname, '..', 'src', 'data', 'fallback_articles.json');

// Ensure parent directory exists
const parentDir = path.dirname(outputPath);
if (!fs.existsSync(parentDir)) {
  fs.mkdirSync(parentDir, { recursive: true });
}

// 1. Helper templates to generate rich, book-style text in Bengali

function getCropTemplate(name, enName, varieties, soil, fertilizers, pests, harvesting, source = 'dae') {
  return `১. ভূমিকা ও জাত পরিচিতি:
${name} (ইংরেজি: ${enName}) বাংলাদেশের কৃষি অর্থনীতি ও খাদ্য নিরাপত্তায় অত্যন্ত গুরুত্বপূর্ণ ভূমিকা পালন করে। বাংলাদেশ কৃষি গবেষণা ইনস্টিটিউট (BARI) বা বাংলাদেশ ধান গবেষণা ইনস্টিটিউট (BRRI) দেশের মাটি ও জলবায়ু উপযোগী বিভিন্ন উন্নত জাত উদ্ভাবন করেছে। এর মধ্যে প্রধান জাতগুলো হলো: ${varieties}। এই জাতগুলো উচ্চ ফলনশীল এবং রোগবালাই প্রতিরোধী।

২. উপযুক্ত মাটি ও জমি প্রস্তুতকরণ:
${name} চাষের জন্য ${soil} সবচেয়ে উপযোগী। জমি তৈরির জন্য ৪-৫টি আড়াআড়ি চাষ ও মই দিয়ে মাটি ঝুরঝুরে করে নিতে হবে। জমি চাষ করার সময় শেষ চাষে পর্যাপ্ত জৈব কম্পোস্ট সার মাটির সাথে ভালোভাবে মিশিয়ে দিতে হবে। পানি নিষ্কাশনের জন্য বেড তৈরি করে চাষ করা বাঞ্ছনীয়, বিশেষ করে বর্ষা মৌসুমের ফসলের জন্য।

৩. সারের সুষম মাত্রা ও প্রয়োগ নিয়ম (বিঘাপ্রতি ৩৩ শতক):
ফসলের কাঙ্ক্ষিত ফলন পেতে সুষম সার ব্যবহার করা আবশ্যক। বিঘাপ্রতি সুপারিশকৃত সারের মাত্রা নিচে দেওয়া হলো:
- গোবর বা পচা কম্পোস্ট সার: ১.৫ - ২ টন (জমি প্রস্তুতের সময়)
- ইউরিয়া সার: ${fertilizers.urea} কেজি (রোপণের পর ৩টি সমান কিস্তিতে)
- টিএসপি সার: ${fertilizers.tsp} কেজি (জমি তৈরির শেষ চাষের সময়)
- এমওপি সার: ${fertilizers.mop} কেজি (অর্ধেক শেষ চাষে, বাকি অর্ধেক ইউরিয়ার সাথে)
- জিপসাম ও দস্তা সার: যথাক্রমে ১০ কেজি ও ১.৫ কেজি (জমি তৈরির সময়)

৪. বালাই ও রোগ প্রতিরোধ ব্যবস্থাপনা:
${name} চাষে প্রধান ক্ষতিকর পোকামাকড় ও রোগবালাইসমূহ হলো: ${pests}।
রোগ দেখা দিলে সাথে সাথে বালাইনাশক স্প্রে করতে হবে:
- ছত্রাকজনিত রোগে প্রতি লিটার পানিতে ২ গ্রাম রিডোমিল গোল্ড (Ridomil Gold ৬৮ডব্লিউজি) অথবা ০.৫ গ্রাম ন্যাটিভো (Nativo ৭৫ডব্লিউজি) স্প্রে করুন।
- পোকা দমনের জন্য সবিক্রন ৪২৫ইসি (Sobicron) ২ মিলি অথবা ভিরটাকো (Virtako ৪০ডব্লিউজি) প্রতি ১০ লিটার পানিতে ৫ গ্রাম মিশিয়ে স্প্রে করুন।

৫. ফসল সংগ্রহ, মাড়াই ও সংরক্ষণ:
${harvesting}। ফসল কাটার পর ভালো করে রোদে শুকিয়ে আর্দ্রতা ১২% এর নিচে নিয়ে আসতে হবে। বায়ুরোধী পাত্র বা গুদামে শুকনা স্থানে সংরক্ষণ করুন যাতে পোকার আক্রমণ না হয়।`;
}

function getDiseaseTemplate(cropName, diseaseName, symptoms, cause, treatment, prevention, source = 'dae') {
  return `১. রোগ পরিচিতি ও কারণ:
${cropName}-এর অন্যতম প্রধান ও মারাত্মক সমস্যা হলো ${diseaseName}। এই রোগটি প্রধানত "${cause}" নামক রোগজীবাণুর আক্রমণের কারণে ঘটে থাকে। অতিরিক্ত আর্দ্রতা, কুয়াশাচ্ছন্ন মেঘলা আবহাওয়া এবং উষ্ণ তাপমাত্রা এই রোগ ছড়াতে সহায়তা করে।

২. রোগের প্রধান লক্ষণসমূহ:
- ${symptoms}
- রোগের আক্রমণ বেশি হলে পুরো গাছটি খুব দ্রুত ঝলসে যায় বা শুকিয়ে মারা যায়, যা মাঠে ফসলের ব্যাপক ক্ষতিসাধন করে।

৩. রাসায়নিক দমন ও সঠিক ঔষধের প্রেসক্রিপশন:
রোগের লক্ষণ প্রকাশ পাওয়া মাত্র বা কুয়াশাচ্ছন্ন আবহাওয়ার পূর্বাভাস পেলে সাথে সাথে নিচের যেকোনো একটি বালাইনাশক ব্যবহার করতে হবে:
${treatment}
- স্প্রে করার সময় অবশ্যই সকালে বা বিকেলের দিকে করতে হবে এবং পুরো গাছ ভালোভাবে ভিজিয়ে দিতে হবে। মিশ্রণ তৈরির সময় মাস্ক ও গ্লাভস ব্যবহার করুন।

৪. জৈব ও চাষাবাদ পদ্ধতি (প্রতিরোধমূলক ব্যবস্থা):
- ${prevention}
- ফসল কাটার পর আক্রান্ত অবশিষ্টাংশ পুড়িয়ে ফেলুন এবং নিয়মিত ফসল চক্র (Crop Rotation) অনুসরণ করুন।`;
}

function getFertilizerTemplate(name, role, deficiency, dosage, application, source = 'dae') {
  return `১. পুষ্টি উপাদানের ভূমিকা ও গুরুত্ব:
${name} উদ্ভিদের দৈহিক বৃদ্ধি, ফুল-ফল উৎপাদন এবং ফলন বৃদ্ধিতে একটি অপরিহার্য পুষ্টি উপাদান। এটি উদ্ভিদের কোষ গঠন, ক্লোরোফিল উৎপাদন এবং বিপাকীয় কার্যকলাপে সক্রিয় ভূমিকা পালন করে।

২. মাটিতে ঘাটতির লক্ষণ (Deficiency Symptoms):
যখন মাটিতে এই পুষ্টি উপাদানের অভাব দেখা দেয়, তখন উদ্ভিদে নিচের লক্ষণগুলো প্রকাশ পায়:
- ${deficiency}
- ঘাটতি দীর্ঘস্থায়ী হলে গাছের বৃদ্ধি স্থবির হয়ে পড়ে এবং ফলন আশঙ্কাজনকভাবে হ্রাস পায়।

৩. বিঘাপ্রতি (৩৩ শতকে) সঠিক প্রয়োগ মাত্রা:
সাধারণ চাষাবাদের জন্য বিঘাপ্রতি সারের সুপারিশকৃত মাত্রা হলো:
- ${dosage}
- মাটির পুষ্টি পরীক্ষা করে সারের মাত্রা কম-বেশি করা যেতে পারে।

৪. সার প্রয়োগের নিয়ম ও সতর্কতা:
- ${application}
- অতিরিক্ত সার প্রয়োগের ফলে উদ্ভিদের ক্ষতি ও মাটির অম্লতা বেড়ে যেতে পারে, তাই অনুমোদিত মাত্রার বেশি সার ব্যবহার করা থেকে বিরত থাকুন।`;
}

function getTechTemplate(name, description, benefits, steps, implementation, source = 'dae') {
  return `১. প্রযুক্তির বিবরণ ও প্রয়োজনীয়তা:
বাংলাদেশ একটি ঘনবসতিপূর্ণ ও কৃষিপ্রধান দেশ। সীমিত জমিতে ক্রমবর্ধমান জনসংখ্যার খাদ্য নিরাপত্তা নিশ্চিত করতে আধুনিক ও টেকসই কৃষি প্রযুক্তি ব্যবহারের কোনো বিকল্প নেই। ${name} হলো এমন একটি উন্নত প্রযুক্তি যা কৃষকদের ${description}।

২. প্রযুক্তির প্রধান সুবিধাসমূহ (Benefits):
- ${benefits}
- এটি ফসল উৎপাদন খরচ কমায় এবং কৃষকের নিট মুনাফা বৃদ্ধি করে।

৩. প্রযুক্তি বাস্তবায়নের সঠিক ধাপসমূহ (Steps):
${steps}

৪. বাংলাদেশে মাঠ পর্যায়ে প্রয়োগ ও সরকারি সহায়তা:
- ${implementation}
- এই প্রযুক্তি বাস্তবায়নে স্থানীয় উপ-সহকারী কৃষি কর্মকর্তা (SAA) এর পরামর্শ ও কারিগরি সহায়তা নেওয়া যেতে পারে।`;
}

