// 3. Assemble and build the full 105 articles list

const allArticles = [];

// Base article structure generator
function createArticle(id, title, content, source_site, source_url, publish_date) {
  return {
    id,
    title,
    content,
    source_site,
    source_url,
    publish_date
  };
}

let articleId = 1;

// A. Add 50 Crop Articles
cropsData.forEach(c => {
  const title = `বারি ও ব্রি নির্দেশিত ${c.name} চাষের আধুনিক বৈজ্ঞানিক ম্যানুয়াল ও বালাই গাইড`;
  const content = getCropTemplate(c.name, c.enName, c.varieties, c.soil, c.fertilizers, c.pests, c.harvesting);
  const source = c.id % 2 === 0 ? 'dae' : 'bari';
  const url = `https://bari.gov.bd/site/technologies/crop-${c.id}`;
  const date = new Date(Date.now() - (articleId * 24 * 60 * 60 * 1000)).toISOString(); // Decrementing dates
  allArticles.push(createArticle(articleId++, title, content, source, url, date));
});

// B. Add 30 Disease/Pest Articles
diseasesData.forEach(d => {
  const title = `${d.crop}-এর ক্ষতিকর ${d.name} সনাক্তকরণ ও আধুনিক বালাই ব্যবস্থাপনা`;
  const content = getDiseaseTemplate(d.crop, d.name, d.symptoms, d.cause, d.treatment, d.prevention);
  const source = d.id % 2 === 0 ? 'dae' : 'bari';
  const url = `https://dae.gov.bd/site/notices/disease-${d.id}`;
  const date = new Date(Date.now() - (articleId * 24 * 60 * 60 * 1000)).toISOString();
  allArticles.push(createArticle(articleId++, title, content, source, url, date));
});

// C. Add 15 Fertilizer & Soil Articles
fertilizersData.forEach(f => {
  const title = `কৃষি পুষ্টি গাইড: ফসলের বাম্পার ফলনে ${f.name}-এর ভূমিকা ও প্রয়োগ বিধি`;
  const content = getFertilizerTemplate(f.name, f.role, f.deficiency, f.dosage, f.application);
  const source = f.id % 2 === 0 ? 'dae' : 'bari';
  const url = `https://bari.gov.bd/site/fertilizers/nutrient-${f.id}`;
  const date = new Date(Date.now() - (articleId * 24 * 60 * 60 * 1000)).toISOString();
  allArticles.push(createArticle(articleId++, title, content, source, url, date));
});

// D. Add 10 Modern Tech Articles
techData.forEach(t => {
  const title = `আধুনিক কৃষি প্রযুক্তি: ${t.name} এবং মাঠ পর্যায়ে বাস্তবায়নের নিয়মাবলী`;
  const content = getTechTemplate(t.name, t.description, t.benefits, t.steps, t.implementation);
  const source = t.id % 2 === 0 ? 'dae' : 'bari';
  const url = `https://dae.gov.bd/site/technologies/tech-${t.id}`;
  const date = new Date(Date.now() - (articleId * 24 * 60 * 60 * 1000)).toISOString();
  allArticles.push(createArticle(articleId++, title, content, source, url, date));
});

// 4. Write to fallback_articles.json
try {
  fs.writeFileSync(outputPath, JSON.stringify(allArticles, null, 2), 'utf8');
  console.log(`\nSuccess! Generated ${allArticles.length} detailed articles in ${outputPath}`);
} catch (e) {
  console.error("Failed to write articles database:", e);
}
